<template>
  <div class="default-layout">
    <header class="layout-header">
      <div class="brand">
        <span class="live-dot" aria-hidden="true"></span>
        <router-link to="/" class="brand-logo">MSM 2</router-link>
        <span class="brand-sep" aria-hidden="true"></span>
        <span class="brand-name">行動訂單管理系統</span>
      </div>
      <nav class="layout-tabs">
        <router-link
          v-for="tab in visibleTabs"
          :key="tab.path"
          :to="tab.path"
          class="tab-item"
          exact
          active-class="is-active"
        >
          <component :is="tab.icon" :size="15" :stroke-width="1.5" class="tab-icon" />
          {{ tab.label }}
        </router-link>
      </nav>
      <div class="layout-profile">
        <div class="profile-text">
          <div>{{ currentUser.name }}</div>
          <div>{{ currentUser.company }}</div>
        </div>
        <button class="logout-button" @click="logoutUser">
          <log-out :size="14" :stroke-width="1.5" />
          登出
        </button>
      </div>
      <!-- 漢堡按鈕（手機） -->
      <button class="hamburger-btn" @click="menuOpen = true" aria-label="開啟選單">
        <menu-icon :size="22" :stroke-width="1.5" />
      </button>
    </header>

    <main class="layout-main">
      <router-view />
      <div class="demo-footer">MSM 2 展示版本 — 所有資料均為模擬資料</div>
    </main>

    <!-- 手機抽屜選單 -->
    <transition name="drawer-fade">
      <div v-if="menuOpen" class="drawer-overlay" @click="menuOpen = false" />
    </transition>
    <transition name="drawer-slide">
      <div v-if="menuOpen" class="drawer-panel">
        <div class="drawer-header">
          <div class="drawer-user">
            <div class="drawer-user-name">{{ currentUser.name }}</div>
            <div class="drawer-user-company">{{ currentUser.company }}</div>
          </div>
          <button class="drawer-close-btn" @click="menuOpen = false" aria-label="關閉選單">
            <x-icon :size="18" :stroke-width="1.5" />
          </button>
        </div>
        <nav class="drawer-nav">
          <router-link
            v-for="tab in visibleTabs"
            :key="tab.path"
            :to="tab.path"
            class="drawer-item"
            exact
            active-class="is-active"
            @click.native="menuOpen = false"
          >
            <component :is="tab.icon" :size="18" :stroke-width="1.5" class="drawer-item-icon" />
            {{ tab.label }}
          </router-link>
        </nav>
        <div class="drawer-footer">
          <button class="drawer-logout-btn" @click="logoutUser">
            <log-out :size="15" :stroke-width="1.5" />
            登出
          </button>
        </div>
      </div>
    </transition>
  </div>
</template>

<script>
import { getCurrentUser } from '../services/auth'
import {
  Home, Package, Heart, ShoppingCart, FileText, ClipboardCheck, Tag, LogOut, Menu, X
} from 'lucide-vue'

export default {
  name: 'DefaultLayout',
  components: { LogOut, MenuIcon: Menu, XIcon: X },
  data () {
    return {
      menuOpen: false,
      tabs: [
        { label: '首頁', path: '/', roles: ['customer', 'sales'], icon: Home },
        { label: '產品', path: '/products', roles: ['customer'], icon: Package },
        { label: '我的最愛', path: '/favorites', roles: ['customer'], icon: Heart },
        { label: '購物車', path: '/cart', roles: ['customer'], icon: ShoppingCart },
        { label: '訂單', path: '/orders', icon: FileText },
        { label: '庫存盤點', path: '/inventory-checks', roles: ['sales'], icon: ClipboardCheck },
        { label: '市場活動', path: '/promotions', roles: ['sales'], icon: Tag }
      ]
    }
  },
  computed: {
    currentUser () {
      return getCurrentUser() || { name: '訪客', company: '' }
    },
    visibleTabs () {
      return this.tabs.filter(tab => {
        if (!tab.roles) return true
        return tab.roles.includes(this.currentUser.role)
      })
    }
  },
  watch: {
    $route () {
      this.menuOpen = false
    }
  },
  methods: {
    logoutUser () {
      this.menuOpen = false
      this.$store.dispatch('logout')
      this.$router.push('/login')
    }
  }
}
</script>

